"use strict";(globalThis.webpackChunksenexic_docs=globalThis.webpackChunksenexic_docs||[]).push([[256],{7674(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docs":[{"type":"link","href":"/docs/","label":"SENEX Documentation","docId":"index","unlisted":false},{"type":"category","label":"AIA and architecture","collapsed":false,"items":[{"type":"link","href":"/docs/architecture/aia_agents","label":"AIA: Local-First Personal Intelligence","docId":"architecture/aia_agents","unlisted":false},{"type":"link","href":"/docs/architecture/intelligent_chain","label":"Intelligent Chain: Coordination and Accountability","docId":"architecture/intelligent_chain","unlisted":false},{"type":"link","href":"/docs/architecture/genome","label":"GENOME: Collective Intelligence Research","docId":"architecture/genome","unlisted":false}],"collapsible":true,"href":"/docs/architecture/"},{"type":"category","label":"Trust and privacy","collapsed":false,"items":[{"type":"link","href":"/docs/privacy/technologies","label":"Privacy Controls and Technology Direction","docId":"privacy/technologies","unlisted":false},{"type":"link","href":"/docs/privacy/mathematical_guarantees","label":"Privacy Assurance and Evidence","docId":"privacy/mathematical_guarantees","unlisted":false},{"type":"link","href":"/docs/privacy/threat_model","label":"Security Threat Model","docId":"privacy/threat_model","unlisted":false},{"type":"link","href":"/docs/privacy/compliance","label":"Compliance and Responsible Data Use","docId":"privacy/compliance","unlisted":false}],"collapsible":true,"href":"/docs/privacy/"},{"type":"link","href":"/docs/tokenomics/","label":"Contribution Economy Research","docId":"tokenomics/index","unlisted":false},{"type":"link","href":"/docs/applications","label":"Applications & Use Cases","docId":"applications","unlisted":false},{"type":"link","href":"/docs/governance","label":"Governance Model","docId":"governance","unlisted":false},{"type":"link","href":"/docs/innovation","label":"Innovation","docId":"innovation","unlisted":false},{"type":"link","href":"/docs/scalability","label":"Scalability & Performance","docId":"scalability","unlisted":false},{"type":"link","href":"/docs/migration","label":"Network Transition & Upgrade Policy","docId":"migration","unlisted":false},{"type":"link","href":"/docs/roadmap","label":"Roadmap","docId":"roadmap","unlisted":false},{"type":"category","label":"Research archive","collapsed":true,"items":[{"type":"link","href":"/docs/aia/","label":"AIA Chain research archive","docId":"aia/index","unlisted":false}],"collapsible":true}]},"docs":{"aia/architecture/secure-remote":{"id":"aia/architecture/secure-remote","title":"Protected remote coordination \u2014 archived research","description":"Public-safe context for an early AIA Chain research path."},"aia/contracts/overview":{"id":"aia/contracts/overview","title":"Experimental coordination contracts \u2014 archived","description":"Historical context for retired AIA Chain contract research."},"aia/guides/contributor-guide":{"id":"aia/guides/contributor-guide","title":"Legacy AIA Chain contributor guide","description":"Retirement notice for obsolete prototype instructions."},"aia/index":{"id":"aia/index","title":"AIA Chain research archive","description":"Historical context for an early SENEX research prototype.","sidebar":"docs"},"applications":{"id":"applications","title":"Applications & Use Cases","description":"SENEX has local-first working foundations and is developing toward a future V1-testnet. The scenarios below are product directions, not claims of production availability, regulatory compliance, clinical effectiveness, financial performance, or network-scale deployment.","sidebar":"docs"},"architecture/aia_agents":{"id":"architecture/aia_agents","title":"AIA: Local-First Personal Intelligence","description":"AIA is the user-facing foundation of SENEX. Its purpose is to help a person work with their own context while keeping control, visibility, and consent close to the point where that context is used.","sidebar":"docs"},"architecture/genome":{"id":"architecture/genome","title":"GENOME: Collective Intelligence Research","description":"GENOME is SENEX\u2019s long-horizon research direction: investigating whether independently controlled AIA participants can cooperate to produce useful shared intelligence without collapsing ownership, consent, or accountability into a central system.","sidebar":"docs"},"architecture/index":{"id":"architecture/index","title":"Architecture Overview","description":"SENEX separates personal intelligence, governed exchange, and network coordination into distinct trust boundaries. This lets each layer be evaluated on its own instead of treating a future network as a prerequisite for useful local software.","sidebar":"docs"},"architecture/intelligent_chain":{"id":"architecture/intelligent_chain","title":"Intelligent Chain: Coordination and Accountability","description":"The Intelligent Chain is the planned network layer for coordinating events among independent SENEX participants. Its public purpose is to make accepted actions consistently observable and accountable without turning private user context into public network data.","sidebar":"docs"},"genome/index":{"id":"genome/index","title":"GENOME research direction","description":"Compatibility route for the current GENOME research overview."},"governance":{"id":"governance","title":"Governance Model","description":"SENEX does not currently operate a public DAO or token-holder governance system. ASHA is simulated and test-only, so it grants no voting rights. Governance work is focused on accountable decision processes for a local-first system under development toward a future V1-testnet.","sidebar":"docs"},"index":{"id":"index","title":"SENEX Documentation","description":"SENEX is developing a local-first intelligence system: personal AIA software works with user-approved context close to the user, while future network components are intended to support governed cooperation between independent participants.","sidebar":"docs"},"innovation":{"id":"innovation","title":"Innovation","description":"SENEX\u2019s central product thesis is that useful intelligence can begin under individual control and later support accountable cooperation without requiring users to surrender unrestricted personal context. Public documentation describes the capabilities and research questions while keeping proprietary constructions and security-sensitive details private.","sidebar":"docs"},"migration":{"id":"migration","title":"Network Transition & Upgrade Policy","description":"There is no deployed public ASHA token, live provider economy, or production SENEX network to migrate. ASHA is simulated and test-only. V1-testnet is a future production-candidate test environment; V1 would be a separate, fresh-genesis production network if approved.","sidebar":"docs"},"privacy/compliance":{"id":"privacy/compliance","title":"Compliance and Responsible Data Use","description":"SENEX\u2019s local-first direction can support data minimization and user control, but architecture alone does not establish legal compliance. Applicable duties depend on the operator, user population, purpose, jurisdiction, data category, deployment, and contracts surrounding a specific use.","sidebar":"docs"},"privacy/index":{"id":"privacy/index","title":"Privacy and Security","description":"SENEX starts from a local-first boundary: personal context should remain within the user-controlled environment unless the user approves a specific use or exchange. The goal is not merely to move storage onto a device, but to make data flows purposeful, limited, visible, and revocable.","sidebar":"docs"},"privacy/mathematical_guarantees":{"id":"privacy/mathematical_guarantees","title":"Privacy Assurance and Evidence","description":"Formal privacy is a property of a precisely defined system under explicit assumptions. It cannot be established by naming a cryptographic technique, publishing an equation, or describing a future architecture. SENEX therefore separates current product controls from research goals and independently validated guarantees.","sidebar":"docs"},"privacy/technologies":{"id":"privacy/technologies","title":"Privacy Controls and Technology Direction","description":"SENEX describes privacy technology by the protection it should provide, not by publishing a recipe for the underlying implementation. Technology names alone do not establish privacy; controls must be connected to a specific data flow, threat, and body of evidence.","sidebar":"docs"},"privacy/threat_model":{"id":"privacy/threat_model","title":"Security Threat Model","description":"This public threat model identifies the classes of risk SENEX considers and the trust boundaries where they arise. It intentionally avoids operational details that could help an attacker reproduce the system, target a control, or infer an internal security design.","sidebar":"docs"},"roadmap":{"id":"roadmap","title":"Roadmap","description":"This roadmap describes evidence and release outcomes, not calendar promises. SENEX has local-first working foundations and is developing toward a future V1-testnet. There is no live public blockchain, token economy, provider settlement, or contribution-reward system.","sidebar":"docs"},"scalability":{"id":"scalability","title":"Scalability & Performance","description":"SENEX does not currently claim production-scale capacity, global availability, linear scaling, a specific uptime level, or guaranteed response time. The working foundation is local-first and remains under development toward a future V1-testnet. Performance claims require reproducible evidence.","sidebar":"docs"},"tokenomics/distribution":{"id":"tokenomics/distribution","title":"Participation & Access","description":"This page previously described token distribution concepts. There is no live ASHA token, public sale, private sale, allocation, entitlement, or distribution program. ASHA is a simulated, test-only accounting unit with no monetary value. See the Contribution Economy Research overview for the current public model."},"tokenomics/incentives":{"id":"tokenomics/incentives","title":"Contribution Incentives","description":"Contribution rewards and provider settlement are not live. ASHA is used only as a simulated, test-only accounting unit and has no monetary value. This page describes desired behavior, not a payout schedule, formula, or offer."},"tokenomics/index":{"id":"tokenomics/index","title":"Contribution Economy Research","description":"SENEX does not operate a public token economy, token sale, staking product, or provider-payment network. ASHA is a simulated, test-only accounting unit used to study coordination scenarios. It is not transferable, tradeable, redeemable, or represented as having monetary value. Provider settlement and contribution rewards are not live.","sidebar":"docs"},"tokenomics/security":{"id":"tokenomics/security","title":"Economic Integrity","description":"The current local-first foundation does not rely on a live stake, token price, or economic-security budget. ASHA is simulated and test-only. This page defines evaluation goals for a possible contribution economy; it does not claim that economic security has been proven."},"tokenomics/staking":{"id":"tokenomics/staking","title":"Participation Commitments","description":"SENEX does not offer staking, delegated staking, yield, revenue sharing, token burning, buy-backs, or a governance return. ASHA is simulated, test-only, and has no monetary value. This page now documents the research question behind operator commitments rather than a financial product."}}}}')}}]);